import React, { useState, useEffect } from 'react';
import { DarkSubTitle } from '../../styles/common';
import * as Styled from './styles';
import { useInView } from 'react-intersection-observer';
import useMobile from '../../helpers/hooks/useMobile';
import useTablet from '../../helpers/hooks/useTablet';
import ContactSection from '../_sections/ContactSection';
import tweex from '../../assets/images/Projects/Tweex.png';
import backoffice from '../../assets/images/Projects/Dashboard.png';
import geox from '../../assets/images/Projects/GeoX.png';
import ain from '../../assets/images/Projects/Ain.png';
import makette from '../../assets/images/Projects/Makette.png';
import pattern from '../../assets/images/Projects/Pattern.png';
import PortfolioCard from '../../components/PortfolioCard';
import setLoaderStatus from '../../helpers/functions/setLoaderStatus';

const Portfolio = () => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
	const isMobile = useMobile();
    const isTablet = useTablet();
    const cards = [
        {
            image: tweex,
            title: 'Tweex',
            description: 'UX/UI, Web development',
            categories: ['UX/UI design', 'Web development'],
            link: 'backoffice',
        },
        {
            image: geox,
            title: 'GeoX',
            description: 'Web development',
            categories: ['Web development'],
            link: 'backoffice',
        },
        {
            image: ain,
            title: 'AIN.UA',
            description: 'Research, UX/UI',
            categories: ['Research', 'UX/UI design'],
            link: 'ain',
        },
        {
            image: backoffice,
            title: 'Backoffice telecom dashboard',
            description: 'Research, UX/UI',
            categories: ['Research', 'UX/UI design'],
            link: 'backoffice',
        },
        {
            image: makette,
            title: 'Makette site',
            description: 'UX/UI, Frontend development',
            categories: ['UX/UI design', 'Web development'],
            link: 'backoffice',
        }
    ]
    const [activeCards,setActiveCards] = useState(cards);
    const [categories, setCategories] = useState({
        'All': true,
        'UX/UI design': false,
        'Research': false,
        'Web development': false,
    });

    useEffect(()=>{
        window.scrollTo(0, 0);
        setLoaderStatus(true);
        
        return setLoaderStatus(false);
    },[])

    return (
        <Styled.PortfolioPageContainer>
            <Styled.PortfolioContainer isTablet={isTablet} isMobile={isMobile} inView={inView} ref={ref}>
                <Styled.TitleContainer>
                    <DarkSubTitle>We create superb solutions</DarkSubTitle>
                </Styled.TitleContainer>
                <Styled.CategoriesContainer>
                    {Object.entries(categories).map((category,index) => {
                        return (
                            <Styled.Category data-ccursor isActive={categories[category[0]]} key={index} onClick={() => {
                                const newState = {};
                                Object.keys(categories).forEach(item => newState[item] = item === category[0] ? true : false);
                                if (category[0] === 'All') {
                                    setActiveCards(cards);
                                } else {
                                    setActiveCards(cards.filter(card => {
                                        let hasCurrentCategory = false;
                                        card.categories.forEach(cardCategory => cardCategory === category[0] ? hasCurrentCategory = true : null)
                                        return hasCurrentCategory ? true : false;
                                    }));
                                }
                                setCategories(newState);
                                }}>{category}</Styled.Category>)
                    })}
                    </Styled.CategoriesContainer>
                <Styled.ColumnsContainer>
                    <Styled.Column>
                        {activeCards.map((card,index) => {
                            if(index < Math.round(activeCards.length / 2)) {
                                return (
                                    <PortfolioCard
                                        key={index}
                                        image={card.image}
                                        title={card.title}
                                        description={card.description}
                                        link={card.link}
                                    />
                                )
                            }
                            return null;
                        })}
                    </Styled.Column>
                    <Styled.Column>
                        {activeCards.map((card,index) => {
                            if(index >= Math.round(activeCards.length / 2 )) {
                                return (
                                    <PortfolioCard
                                    key={index}
                                    image={card.image}
                                    title={card.title}
                                    description={card.description}
                                    link={card.link}
                                />
                                )
                            }
                            return null;
                        })}
                        {(activeCards.length % 2 || isMobile) && (
                            <PortfolioCard
                                image={pattern}
                                title={'Your project could be here! Contact us and get started'}
                                description={'UX/UI, Frontend development'}
                            />
                        )}
                    </Styled.Column>
                </Styled.ColumnsContainer>
            </Styled.PortfolioContainer>
            <ContactSection style={{paddingTop: 0}}/>
        </Styled.PortfolioPageContainer>
    );
};

export default Portfolio;
